# write_frontend.ps1 - run once from inside RAG-BANK:
#     powershell -ExecutionPolicy Bypass -File .\write_frontend.ps1
$ErrorActionPreference = 'Stop'
$b = ''
[System.IO.File]::WriteAllBytes((Join-Path (Get-Location) 'frontend/index.html'), [System.Convert]::FromBase64String($b))
Write-Host 'wrote frontend/index.html' -ForegroundColor Green
